const raw = $input.all().map(i => i.json);
const businesses = raw.length === 1 && Array.isArray(raw[0]) ? raw[0] : raw;
const results = [];
for (const biz of businesses) {
  const id = biz.business_id || biz.name;
  if (!id || id === '_template') continue;
  results.push({ json: { businessId: id, businessName: biz.name || id, businessPath: 'memory-bank/businesses/' + id, repo_name: biz.repo_name || id } });
}
if (results.length === 0) return [{ json: { _skip: true, _reason: 'No active businesses found' } }];
return results;

// Compute report date strings for file lookups
const now = new Date();
const today = now.toISOString().split('T')[0];

// Last Monday
const dayOfWeek = now.getDay();
const daysToMonday = (dayOfWeek + 6) % 7; // 0=Sun => 6, 1=Mon => 0, ..., 5=Fri => 4
const lastMonday = new Date(now);
lastMonday.setDate(now.getDate() - (daysToMonday === 0 ? 7 : daysToMonday));
const lastMondayStr = lastMonday.toISOString().split('T')[0];

// Last Tuesday
const daysToTuesday = (dayOfWeek + 5) % 7; // 0=Sun => 5, 1=Mon => 6, 2=Tue => 0, ..., 5=Fri => 3
const lastTuesday = new Date(now);
lastTuesday.setDate(now.getDate() - (daysToTuesday === 0 ? 7 : daysToTuesday));
const lastTuesdayStr = lastTuesday.toISOString().split('T')[0];

// Pass through business context
const businessId = $('Filter Active Businesses').first().json.businessId;
const businessPath = $('Filter Active Businesses').first().json.businessPath;
const stateContent = $('Read State').first().json.content || '';
const strategyContent = $('Read Strategy (save SHA)').first().json.content || '';
const strategySha = $('Read Strategy (save SHA)').first().json.sha || '';

return [{
  json: {
    today,
    lastMonday: lastMondayStr,
    lastTuesday: lastTuesdayStr,
    businessId,
    businessPath,
    stateContent,
    strategyContent,
    strategySha
  }
}];

// Merge all context into a single prompt
const dates = $('Compute Report Dates').first().json;
const businessId = dates.businessId;
const stateContent = dates.stateContent;
const strategyContent = dates.strategyContent;

// Safely extract content from optional reads (may have failed)
let ceoReport = '';
try { ceoReport = $('Read Latest CEO Report').first().json.content || ''; } catch(e) { ceoReport = '[No CEO report found for this period]'; }

let discoveryOpps = '';
try { discoveryOpps = $('Read Latest Discovery Opportunities').first().json.content || ''; } catch(e) { discoveryOpps = '[No discovery opportunities found for this period]'; }

let comptrollerReview = '';
try { comptrollerReview = $('Read Latest Comptroller Review').first().json.content || ''; } catch(e) { comptrollerReview = '[No comptroller review found for this period]'; }

let productReport = '';
try { productReport = $('Read Latest Product Report').first().json.content || ''; } catch(e) { productReport = '[No product report found for this period]'; }

const prompt = `Today is ${dates.today}. You are the Portfolio Orchestrator for The Forge (Forge Technologies, Inc.).

You have cross-portfolio intelligence responsibilities. You review ALL agent outputs holistically to identify patterns, risks, and opportunities across the entire portfolio.

Here is the current portfolio data:

## Business: ${businessId}

### Current State
${stateContent}

### Current Strategy
${strategyContent}

### Latest CEO Report (${dates.lastMonday})
${ceoReport}

### Latest Discovery Opportunities (${dates.lastTuesday})
${discoveryOpps}

### Latest Comptroller Review (${dates.lastMonday})
${comptrollerReview}

### Latest Product Report (${dates.lastMonday})
${productReport}

---

Perform your weekly portfolio review. You MUST cover ALL of the following:

1. **Holistic Agent Output Review:** Synthesize findings from the CEO report, comptroller review, and product report. Are agents aligned? Any contradictions or blind spots?

2. **Discovery Opportunity Evaluation:** Review the latest discovery opportunities. Evaluate each for portfolio fit: Does it complement existing businesses? Is the market large enough (100K+ customers)? Does it match our clone-and-improve from Acquire.com strategy? Recommend accept/reject/defer for each.

3. **Revenue Ceiling Enforcement:** Can each business plausibly reach $100K MRR? If ceiling is $15-30K, flag it (still valuable, but no breakout investment).

4. **Distribution Channel Intelligence:** Which keywords are converting? Which content formats drive signups? Identify cross-portfolio patterns.

5. **Breakout Detection:** Any business showing >30% MoM growth? Flag immediately for budget increase.

6. **Kill/Sell Assessment:** Any business with no revenue after 60 days? Any plateaued at $5-30K MRR (sell candidate on Acquire.com at 3-4x annual)?

7. **Content Reuse:** Can winning content strategies from one business be adapted for others in related verticals?

8. **UGC Graduation:** Any business at $5K+ MRR still running 100% AI content? Flag for UGC transition.

9. **Token Budget Audit:** Are AI costs per business reasonable for the stage? Any businesses hitting token caps without results (kill signal)?

---

**OUTPUT FORMAT:**

First, output your full portfolio review report in markdown.

Then, if any strategic adjustments are needed for the business strategy, output them between delimiters. The content between the delimiters should be the COMPLETE updated strategy.md file content (not a diff).

===STRATEGY_UPDATE_START===
[Full updated strategy.md content here, only if changes are needed]
===STRATEGY_UPDATE_END===

If no strategic adjustments are needed, do NOT include the strategy update delimiters.`;

return [{ json: { prompt, strategySha: dates.strategySha, businessId, businessPath: dates.businessPath } }];

// Parse the LLM output: extract report and optional strategy update
const fullOutput = $('Orchestrator LLM Chain').first().json.text || '';
const strategySha = $('Merge Context').first().json.strategySha;
const businessId = $('Merge Context').first().json.businessId;
const businessPath = $('Merge Context').first().json.businessPath;

let report = fullOutput;
let strategyUpdate = '';
let hasStrategyUpdate = false;

const startDelim = '===STRATEGY_UPDATE_START===';
const endDelim = '===STRATEGY_UPDATE_END===';

const startIdx = fullOutput.indexOf(startDelim);
const endIdx = fullOutput.indexOf(endDelim);

if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
  report = fullOutput.substring(0, startIdx).trim();
  strategyUpdate = fullOutput.substring(startIdx + startDelim.length, endIdx).trim();
  hasStrategyUpdate = true;
}

return [{
  json: {
    report,
    strategyUpdate,
    hasStrategyUpdate,
    strategySha,
    businessId,
    businessPath
  }
}];
